import { AppModule } from './src/app.module';
import { LaboratoriesService } from './src/laboratories/laboratories.service';

async function test() {
  try {
    const moduleRef = await Test.createTestingModule({ imports: [AppModule] }).compile();
    const service: any = moduleRef.get(LaboratoriesService, { strict: false });
    const created = service.create({ name: 'Lab Alpha' });
    if (!created.createdAt || !created.updatedAt) throw new Error('[VALIDATION_ERROR] create() no estableció createdAt y updatedAt');
    const firstUpdate = created.updatedAt;
    await new Promise(r => setTimeout(r, 10));
    const updated = service.update(created.id, { name: 'Lab Beta' });
    if (updated.updatedAt <= firstUpdate) throw new Error('[VALIDATION_ERROR] update() no actualizó updatedAt correctamente');
    if (updated.createdAt !== created.createdAt) throw new Error('[VALIDATION_ERROR] update() modificó createdAt (no debería hacerlo)');
    console.log('Test pasado correctamente');
  } catch (e) { throw e; }
}
