import { Injectable, NotFoundException } from '@nestjs/common';
import { CreateLaboratoryDto } from './dto/create-laboratory.dto';
import { UpdateLaboratoryDto } from './dto/update-laboratory.dto';
import { Laboratory } from './entities/laboratory.entity';

@Injectable()
export class LaboratoriesService {
  private laboratories: Laboratory[] = [];
  private idCounter = 1;

  create(createLaboratoryDto: any) {
    const timestamp = new Date().getTime();
    const newLab: Laboratory = {
      id: this.idCounter++,
      name: createLaboratoryDto.name?.trim().toLocaleLowerCase(),
      createdAt: timestamp,
      updatedAt: timestamp
    };
    this.laboratories.push(newLab);
    return newLab;
  }

  findAll() {
    return this.laboratories;
  }

  findOne(id: number) {
    const lab = this.laboratories.find(l => l.id === id);
    if (!lab) throw new NotFoundException('Lab not found');
    return lab;
  }

  update(id: number, updateLaboratoryDto: any) {
    const lab = this.findOne(id);
    if (updateLaboratoryDto.name) {
      lab.name = updateLaboratoryDto.name.trim().toLocaleLowerCase();
    }
    lab.updatedAt = new Date().getTime();
    return lab;
  }

  remove(id: number) {
    const index = this.laboratories.findIndex(l => l.id === id);
    if (index === -1) throw new NotFoundException('Lab not found');
    return this.laboratories.splice(index, 1)[0];
  }
}

