import { Test } from '@nestjs/testing';
import { AppModule } from './src/app.module';
import { SpacesService } from './src/spaces/spaces.service';
import { ReservationsService } from './src/reservations/reservations.service';
import { NotFoundException } from '@nestjs/common';
import * as fs from 'fs';

async function test() {
  try {
    if (!fs.existsSync('./src/spaces/spaces.module.ts')) throw new Error('[VALIDATION_ERROR] Falta spaces.module.ts');
    if (!fs.existsSync('./src/reservations/reservations.module.ts')) throw new Error('[VALIDATION_ERROR] Falta reservations.module.ts');

    const moduleRef = await Test.createTestingModule({ imports: [AppModule] }).compile();
    const spacesService: any = moduleRef.get(SpacesService, { strict: false });
    const reservationsService: any = moduleRef.get(ReservationsService, { strict: false });

    const space = spacesService.create({ name: ' Sala A ' });
    if (space.name !== 'sala a') throw new Error('[VALIDATION_ERROR] El nombre del espacio no se normalizó correctamente');
    if (!space.createdAt || !space.updatedAt) throw new Error('[VALIDATION_ERROR] El espacio no tiene timestamps');

    let threw = false;
    try { reservationsService.create({ user: 'John', spaceId: 999 }); } catch(e) { if(e instanceof NotFoundException) threw = true; }
    if (!threw) throw new Error('[VALIDATION_ERROR] ReservationsService no validó el spaceId inexistente');

    const reservation = reservationsService.create({ user: 'John', spaceId: space.id });
    if (reservation.spaceId !== space.id) throw new Error('[VALIDATION_ERROR] Error al crear reserva');
    if (!reservation.createdAt) throw new Error('[VALIDATION_ERROR] La reserva no tiene timestamps');

    console.log('Test pasado correctamente');
  } catch (e) { throw e; }
}
test();
